create table knowledge_base
(
    id          varchar(128)               not null
        primary key,
    title       varchar(255) default NULL::character varying,
    description text,
    type        varchar(32)                not null,
    tags        jsonb        default 'null'::jsonb,
    del_flag    boolean      default false not null,
    updated_at  timestamp with time zone,
    created_at  timestamp with time zone,
    user_id     varchar(36),
    "order"     integer      default 0     not null,
    pub_type    varchar(32)                not null,
    pub_date    date,
    source      varchar(32)                not null,
    group_id    varchar(255) default NULL::character varying
);

alter table knowledge_base
    owner to myscale_kb_backend;

create index knowledge_base_id_756aad25_like
    on knowledge_base (id varchar_pattern_ops);

create index knowledge_base_user_id_160df011
    on knowledge_base (user_id);

create index knowledge_base_user_id_160df011_like
    on knowledge_base (user_id varchar_pattern_ops);

